    PRIMARY KEY (`id`),
    UNIQUE KEY `uk_notice_user` (`notice_id`,`user_id`),
    KEY           `idx_user` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='公告阅读记录表';

